function apply(db) {
  const cur = db.exec("SELECT value FROM settings WHERE key = 'kb_subpages_ver'");
  const ver = cur.length ? cur[0].values[0][0] : null;
  if (ver >= VERSION) return 0;
  for (const p of pages) {
    db.run("INSERT OR REPLACE INTO keyboard_pages (page, name, cols, rows) VALUES (?,?,?,?)",
      [p.page, p.name, p.cols, p.rows]);
  }
  db.run("DELETE FROM keyboard_buttons WHERE page > 5");
  const stmt = db.prepare("INSERT INTO keyboard_buttons (id,label,type,price,image,color,bg_color,parent_id,category_filter,alpha_range,sort_order,position,page,grid_row,grid_col,col_span,row_span,product_id,active) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)");
  for (const b of buttons) {
    stmt.run([b.id,b.label,b.type,b.price,b.image,b.color,b.bg_color,b.parent_id,b.category_filter,b.alpha_range,b.sort_order,b.position,b.page,b.grid_row,b.grid_col,b.col_span,b.row_span,b.product_id,b.active]);
  }
  stmt.free();
  db.run("INSERT OR REPLACE INTO settings (key, value) VALUES ('kb_subpages_ver', ?)", [VERSION]);
  return buttons.length;
}

module.exports = { VERSION, pages, buttons, apply };
